+    /// Use draft model to generate speculative tokens (2-4 tokens ahead)
+    /// This breaks the memory bandwidth barrier by generating multiple tokens per main model decode
+    fn speculateWithDraftModel(self: *Self, cell: *Cell) !void {
+        const draft_ctx = self.draft_ctx orelse return;
+        var draft_batch = self.draft_batch orelse return;
+        const draft_sampler = self.draft_sampler orelse return;
+        const draft_model = self.draft_model orelse return;
+
+        // Prepare draft batch with cell's recent tokens as context
+        draft_batch.n_tokens = 0;
+        var batch_idx: usize = 0;
+
+        // Add last token to draft context (single token input for auto-regressive generation)
+        const last_token = cell.recent_tokens[7]; // Most recent token
+        draft_batch.token[batch_idx] = last_token;
+        draft_batch.pos[batch_idx] = @intCast(cell.pos - 1);
+        draft_batch.n_seq_id[batch_idx] = 1;
+        draft_batch.seq_id[batch_idx][0] = @intCast(cell.id);
+        draft_batch.logits[batch_idx] = 1;
+        batch_idx += 1;
+
+        draft_batch.n_tokens = @intCast(batch_idx);
+
+        // Run draft model to generate candidates (generate 2-4 tokens)
+        const max_draft_tokens: usize = 4;
+        var drafted_count: usize = 0;
+
+        while (drafted_count < max_draft_tokens) {
+            // Decode with draft model
+            if (c.llama_decode(draft_ctx, draft_batch) != 0) {
+                break; // Draft failed, stop speculation
+            }
+
+            // Sample from draft model (greedy)
+            const draft_token = c.llama_sampler_sample(draft_sampler, draft_ctx, @intCast(draft_batch.n_tokens - 1));
+
+            // Check if draft model predicted EOS
+            const vocab = draft_model.getVocab();
+            if (c.llama_vocab_is_eog(vocab, draft_token)) {
+                break; // Stop speculation at EOS
+            }
+
+            // Add drafted token to speculation list
+            try cell.speculated_tokens.append(cell.allocator, draft_token);
+            drafted_count += 1;
+
+            // Prepare next draft batch with the generated token
+            draft_batch.n_tokens = 0;
+            draft_batch.token[0] = draft_token;
+            draft_batch.pos[0] = @intCast(cell.pos + @as(u32, @intCast(drafted_count)) - 1);
+            draft_batch.n_seq_id[0] = 1;
+            draft_batch.seq_id[0][0] = @intCast(cell.id);
+            draft_batch.logits[0] = 1;
+            draft_batch.n_tokens = 1;
+        }
+
+        if (drafted_count > 0) {
+            cell.speculation_start_pos = cell.pos;
+
+            // Queue drafted tokens for verification by main model
+            for (cell.speculated_tokens.items) |spec_token| {
+                try cell.queueInput(&[_]c.llama_token{@intCast(spec_token)});
+            }
+
+            logger.info("Cell {} speculating {} tokens from draft model", .{ cell.id, drafted_count });
+        }
+    }
